6	<title>Kobra S1 Maintenance Guide · Anycubic</title>
7	<style>
8	  :root {
9	    --accent: #3a6093;
10	    --bg: #f7f9fc;
11	    --card: #fff;
12	    --border: #dce3ed;
13	    --text: #1a1f2b;
14	    --muted: #5f6b7a;
15	    --warn: #e67e22;
16	    --danger: #c0392b;
17	    --ok: #27ae60;
18	  }
19	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
20	  body {
21	    font-family: system-ui, -apple-system, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
22	    background: var(--bg);
23	    color: var(--text);
24	    line-height: 1.6;
25	    padding: 0 1rem 3rem;
26	  }
27	  .max { max-width: 880px; margin: 0 auto; }
28	
29	  /* header */
30	  header {
31	    background: var(--accent);
32	    color: #fff;
33	    padding: 2rem 1.5rem 1.5rem;
34	    border-radius: 0 0 1rem 1rem;
35	    text-align: center;
36	    margin: 0 -1rem 2rem;
37	  }
38	  header h1 { font-size: 1.7rem; font-weight: 700; margin-bottom: .3rem; }
39	  header p { font-size: .95rem; opacity: .85; }
40	
41	  /* sections */
42	  section { margin-bottom: 2rem; }
43	  .card {
44	    background: var(--card);
45	    border: 1px solid var(--border);
46	    border-radius: .75rem;
47	    padding: 1.5rem;
48	    margin-bottom: 1.25rem;
49	    box-shadow: 0 1px 3px rgba(0,0,0,.04);
50	  }
51	  .card h2 {
52	    font-size: 1.2rem;
53	    color: var(--accent);
54	    display: flex;
55	    align-items: center;
56	    gap: .5rem;
57	    margin-bottom: .75rem;
58	    padding-bottom: .5rem;
59	    border-bottom: 2px solid var(--border);
60	  }
61	  .card h2 .badge {
62	    font-size: .7rem;
63	    font-weight: 600;
64	    background: var(--accent);
65	    color: #fff;
66	    padding: .15rem .55rem;
67	    border-radius: 20px;
68	    margin-left: auto;
69	  }
70	  .card h3 {
71	    font-size: 1rem;
72	    margin: 1rem 0 .35rem;
73	    color: #1a1f2b;
74	  }
75	  .card h3:first-of-type { margin-top: 0; }
76	  .card ul, .card ol { padding-left: 1.4rem; margin: .4rem 0 .6rem; }
77	  .card li { margin-bottom: .3rem; }
78	  .card p { margin: .35rem 0; }
79	
80	  /* alerts */
81	  .alert {
82	    border-radius: .5rem;
83	    padding: .7rem 1rem;
84	    margin: .6rem 0;
85	    font-size: .92rem;
86	  }
87	  .alert-warn {
88	    background: #fef6e4;
89	    border-left: 4px solid var(--warn);
90	    color: #7a4f0e;
91	  }
92	  .alert-danger {
93	    background: #fce8e6;
94	    border-left: 4px solid var(--danger);
95	    color: #8b2a1e;
96	  }
97	  .alert-info {
98	    background: #e8f0fa;
99	    border-left: 4px solid var(--accent);
100	    color: #1f3a5f;
101	  }
102	  .alert-ok {
103	    background: #e6f7ee;
104	    border-left: 4px solid var(--ok);
105	    color: #166534;
106	  }
107	
108	  /* schedule table */
