      <tr><td>Spring Steel Magnetic Platform</td><td>S010418</td><td>$46.00</td><td><a href="https://store.anycubic.com/products/magnetic-platform" target="_blank">store.anycubic.com/products/magnetic-platform</a></td></tr>
      <tr><td>Air Filter</td><td>S010271</td><td>$9.90</td><td><a href="https://store.anycubic.com/products/air-filter" target="_blank">store.anycubic.com/products/air-filter</a></td></tr>
      <tr><td>Heatbed Nozzle Wiper</td><td>S010225</td><td>$9.99</td><td><a href="https://store.anycubic.com/products/heatbed-nozzle-wiper" target="_blank">store.anycubic.com/products/heatbed-nozzle-wiper</a></td></tr>
      <tr><td>Filament Hub (ACE Pro)</td><td>S010247</td><td>$13.99</td><td><a href="https://store.anycubic.com/products/filament-hub" target="_blank">store.anycubic.com/products/filament-hub</a></td></tr>
      <tr><td>AirPure 2.0 (HEPA filter)</td><td>AP20WH0A-M</td><td>$49.99</td><td><a href="https://store.anycubic.com/products/airpure-2-0" target="_blank">store.anycubic.com/products/airpure-2-0</a></td></tr>
      <tr><td>Double-sided 3D Effect Plate</td><td>S010334</td><td>$34.99</td><td><a href="https://store.anycubic.com/products/3d-effect-plate" target="_blank">store.anycubic.com/products/3d-effect-plate</a></td></tr>
